### Full Peer Example

```javascript
const PeerInstance = new ZYNQ.peer({
  video: true,
  audio: true
})

PeerInstance.on("open", id => {
  console.log("My ID:", id)
})

PeerInstance.on("data", msg => {
  console.log(msg)
})

PeerInstance.connect("other-id")
PeerInstance.send("hello 👽")
```
